import{_ as e,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Enable Single Sign On","description":"","frontmatter":{"title":"Enable Single Sign On","slug":"enable-single-sign-on"},"headers":[],"relativePath":"account-hub/enable-single-sign-on.md","filePath":"account-hub/enable-single-sign-on.md"}'),i={name:"account-hub/enable-single-sign-on.md"};function d(n,t,s,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Branch now uses Auth0 to provide a more secure Single Sign-On (SSO) experience.</p><p>To take advantage of these improvements, you will need to migrate your existing SSO configuration using the new process.</p><p>Please see the <a href="./configure-sso-with-auth0.html">Configure SSO With Auth0</a> guide for complete instructions.</p><p><strong>Migration is required before January 2026</strong>, when this current SSO method will be <strong>deprecated</strong>.</p></div><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch offers Security Assertion Markup Language (SAML) / Single Sign-on (SSO) support for Branch Dashboard. This allows you to use your identity provider (IdP) to centralize access to various services for your team and leverage existing directory systems and security groups.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ol><li>The IdP you are using supports SAML (ex. Okta, OneLogin, Microsoft Azure AD, etc.)</li><li>Your company&#39;s IT department ready to configure SAML that knows your company&#39;s email domains</li><li><a href="./add-manage-users-roles-permissions-access.html">Admin Access Level</a> to your Branch account</li></ol><h2 id="enable-sso" tabindex="-1">Enable SSO <a class="header-anchor" href="#enable-sso" aria-label="Permalink to &quot;Enable SSO&quot;">​</a></h2><h3 id="_1-add-branch-to-your-identity-provider" tabindex="-1">1. Add Branch to your Identity Provider <a class="header-anchor" href="#_1-add-branch-to-your-identity-provider" aria-label="Permalink to &quot;1. Add Branch to your Identity Provider&quot;">​</a></h3><p>Add Branch to your IdP - Add the following SAML attribute mappings:</p><table tabindex="0"><thead><tr><th>SAML Attribute</th><th>Field it Should Map to in Your IdP</th></tr></thead><tbody><tr><td><code>email</code></td><td>User&#39;s email address</td></tr><tr><td><code>firstName</code></td><td>User&#39;s first name</td></tr><tr><td><code>lastName</code></td><td>User&#39;s last name</td></tr></tbody></table><p>Here is some initial information that your IdP might ask for:</p><table tabindex="0"><thead><tr><th>IdP Field</th><th>Value</th></tr></thead><tbody><tr><td>Platform</td><td>Web</td></tr><tr><td>Sign-on method</td><td>SAML 2.0</td></tr><tr><td>Application name</td><td>Branch</td></tr><tr><td>Logo</td><td><a href="https://www.branch.io/brand/#kit" target="_blank" rel="noreferrer">Download here</a></td></tr><tr><td>ACS URL</td><td><code>https://&lt;subdomain&gt;.dashboard.branch.io/sso/callback</code></td></tr><tr><td>Entity ID or Audience URI</td><td><code>https://&lt;subdomain&gt;.dashboard.branch.io</code></td></tr><tr><td>SP Metadata</td><td>None</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">SSO Name ID Format</p><p>Branch only supports SSO Name ID Formats, basic or unspecified.</p></div><p>Once this is complete, your IdP will provide you with details that you&#39;ll need to add to the Branch Dashboard to enable SSO.</p><h3 id="_2-add-your-idp-details-back-to-branch" tabindex="-1">2. Add Your IdP Details Back to Branch <a class="header-anchor" href="#_2-add-your-idp-details-back-to-branch" aria-label="Permalink to &quot;2. Add Your IdP Details Back to Branch&quot;">​</a></h3><p>In the Branch Dashboard navigate to <strong>Account Settings &gt; SSO tab</strong>. If you&#39;re already logged into the Branch Dashboard, you can click <a href="https://dashboard.branch.io/account-settings/sso" target="_blank" rel="noreferrer">here</a> to go there directly. Enable SSO by toggling <strong>Enable SAML/SSO</strong>.</p><p>Next, add the following information:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Email Domains</td><td>Provided by your company (likely IT);.Team members on the email domains used to be able to log in via SAML/SSO</td></tr><tr><td>Branded Login Domain</td><td>Provided by your company (likely IT). Where your users will be able to log in to Branch. Typically your company name. Lowercase letters, numbers, underscores, and dashes only.</td></tr><tr><td>Identity provider Entity ID</td><td>Provided by your IdP. The URL of your IdP (SAML 2.0).</td></tr><tr><td>Identity provider SSO URL</td><td>Provided by your IdP. The SAML endpoint from your identity provider.</td></tr><tr><td>Public x509 certificate</td><td>Provided by your IdP. Copy/paste this from your IdP from when you added Branch.</td></tr></tbody></table><p>Click <strong>Save</strong>.</p><h3 id="_3-add-users-to-branch-in-your-idp" tabindex="-1">3. Add Users to Branch in Your IdP <a class="header-anchor" href="#_3-add-users-to-branch-in-your-idp" aria-label="Permalink to &quot;3. Add Users to Branch in Your IdP&quot;">​</a></h3><p>Give the appropriate users access to Branch in your identity provider. When you add users to Branch via your IdP, you will also have to add them to the team for the appropriate apps in the Branch Dashboard. You can do this on the <a href="https://dashboard.branch.io/account-settings/team" target="_blank" rel="noreferrer">Account Settings &gt; Team</a> page for each app that you want the user to have access to.</p><div class="danger custom-block"><p class="custom-block-title">Users on Branch But Not Your IdP</p><p>Single Sign-On (SSO) authentication is applied according to the user&#39;s email domain. For team members under your email domain listed in the Branch Dashboard, access must be granted via your Identity Provider (IdP). If these users are not authorized in the IdP, they will be unable to access the Branch Dashboard once SSO is activated.</p><p>Users with email domains not associated with your organization will continue to use the standard login procedure.</p></div><p>SSO is now enabled and users will have to login via your branded subdomain. When users on your claimed email domain(s) try to log in, reset their password, or sign up the regular way via <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">https://dashboard.branch.io</a>, they will be redirected to your branded subdomain and your IdP login page.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><ul><li><a href="./does-branch-support-just-in-time-or-scim-account-provisioning.html">Does Branch support just-in-time or SCIM account provisioning?</a></li></ul>',24)])])}const b=e(i,[["render",d]]);export{p as __pageData,b as default};
